const s = $('Query Stats').first().json;
const recent = $('Last 10 Processed').all().map(i => i.json);
const failures = $('Failed Companies').all().map(i => i.json);

// Proxy stats
let proxyData = {};
try {
  const px = $('Proxy Pool Stats').all();
  px.forEach(p => { proxyData[p.json.status] = { cnt: p.json.cnt, avg_ms: p.json.avg_ms }; });
} catch(e) {}

// Logo stats
let logoData = {};
try {
  logoData = $('Logo Stats').first().json;
} catch(e) {}

const total = parseInt(s.total) || 0;
const enriched = parseInt(s.enriched) || 0;
const failed = parseInt(s.failed) || 0;
const failedRetry = parseInt(s.failed_retry) || 0;
const notFound = parseInt(s.not_found) || 0;
const fixedByRetry = parseInt(s.fixed_by_retry) || 0;
const TARGET = 872051;

const t1 = parseInt(s.tier1) || 0;
const t2 = parseInt(s.tier2) || 0;
const t3 = parseInt(s.tier3) || 0;
const t4 = parseInt(s.tier4) || 0;
const t5 = parseInt(s.tier5) || 0;

const TARGET_T1 = 915, TARGET_T2 = 798, TARGET_T3 = 4410, TARGET_T4 = 4700, TARGET_T5 = 861228;

const errProxy = parseInt(s.err_proxy) || 0;
const errParse = parseInt(s.err_parse) || 0;
const errNotFound = parseInt(s.err_not_found) || 0;

const avgSec = parseFloat(s.avg_sec) || 0;
const remaining = TARGET - total;
const rate = avgSec > 0 ? Math.round(3600 / (avgSec + 15)) : 0;
const etaHours = rate > 0 ? Math.round(remaining / rate) : 0;
const etaDays = rate > 0 ? (etaHours / 24).toFixed(1) : '?';

const processed = total - notFound;
const successRate = processed > 0 ? ((enriched / processed) * 100).toFixed(1) : '0';
const totalErrors = failed + failedRetry;

// Logo KPIs
const logosOk = parseInt(logoData.logos_ok) || 0;
const logosFailed = parseInt(logoData.logos_failed_max) || 0;
const logosRetrying = parseInt(logoData.logos_retrying) || 0;
const logosPending = parseInt(logoData.logos_pending) || 0;
const logosTotal = parseInt(logoData.total_enriched) || 0;
const logoPct = logosTotal > 0 ? ((logosOk / logosTotal) * 100).toFixed(1) : '0';

// Proxy summary
const pxActive = proxyData.active || { cnt: 0, avg_ms: '?' };
const pxTesting = proxyData.testing || { cnt: 0, avg_ms: '?' };
const pxCooldown = proxyData.cooldown || { cnt: 0, avg_ms: '?' };
const pxBlacklisted = proxyData.blacklisted || { cnt: 0, avg_ms: '?' };

return { json: {
  '📊 PIPELINE MONITOR v2.1': '═══════════════════════════════',
  target: `${TARGET.toLocaleString()} empresas (Padrón RUC completo)`,
  arquitectura: '10 batches × ~87K | Retry cada 2h',

  '🎯 PROGRESO': '═══════════════════════════════',
  progress: `${total.toLocaleString()} / ${TARGET.toLocaleString()} (${((total/TARGET)*100).toFixed(2)}%)`,
  remaining: `${remaining.toLocaleString()} pendientes`,
  eta: `~${etaHours}h (~${etaDays} días)`,
  rate: `~${rate}/hora`,

  '✅ RESULTADOS': '═══════════════════════════════',
  enriched: enriched.toLocaleString(),
  not_found_datosperu: `${notFound.toLocaleString()} (permanente, no retry)`,
  failed_pending: `${failed.toLocaleString()} (primer intento)`,
  failed_after_retry: `${failedRetry.toLocaleString()} (retry fallido)`,
  fixed_by_retry: `${fixedByRetry.toLocaleString()} (recuperados)`,
  success_rate: `${successRate}% (excluyendo not_found)`,

  '📈 POR TIER': '═══════════════════════════════',
  tier1: `${t1.toLocaleString()} / ${TARGET_T1.toLocaleString()} (${((t1/TARGET_T1)*100).toFixed(1)}%) — ≥1000 emp`,
  tier2: `${t2.toLocaleString()} / ${TARGET_T2.toLocaleString()} (${((t2/TARGET_T2)*100).toFixed(1)}%) — 500-999`,
  tier3: `${t3.toLocaleString()} / ${TARGET_T3.toLocaleString()} (${((t3/TARGET_T3)*100).toFixed(1)}%) — 100-499`,
  tier4: `${t4.toLocaleString()} / ${TARGET_T4.toLocaleString()} (${((t4/TARGET_T4)*100).toFixed(1)}%) — 50-99`,
  tier5: `${t5.toLocaleString()} / ${TARGET_T5.toLocaleString()} (${((t5/TARGET_T5)*100).toFixed(1)}%) — 0-49`,

  '❌ ERRORES (por tipo)': '═══════════════════════════════',
  proxy_errors: `${errProxy} (proxy caído/blacklisted)`,
  parse_errors: `${errParse} (HTML inesperado)`,
  not_found_errors: `${errNotFound} (no existe en DatosPeru)`,
  total_active_errors: totalErrors,

  '🖼️ LOGOS': '═══════════════════════════════',
  logos_downloaded: `${logosOk.toLocaleString()} / ${logosTotal.toLocaleString()} (${logoPct}%)`,
  logos_pending: `${logosPending.toLocaleString()} (sin intentar)`,
  logos_retrying: `${logosRetrying.toLocaleString()} (1-2 intentos, reintentando)`,
  logos_failed: `${logosFailed.toLocaleString()} (3+ intentos, descartados)`,

  '🔌 PROXIES': '═══════════════════════════════',
  proxy_active: `${pxActive.cnt} (avg ${pxActive.avg_ms || '?'}ms)`,
  proxy_testing: `${pxTesting.cnt}`,
  proxy_cooldown: `${pxCooldown.cnt}`,
  proxy_blacklisted: `${pxBlacklisted.cnt}`,

  '⏱️ TIMING': '═══════════════════════════════',
  avg_scrape: `${s.avg_sec || 'N/A'}s`,
  avg_fields: s.avg_fields || 'N/A',
  wait_per_item: '15s',
  started_at: s.started_at || 'N/A',
  last_updated: s.last_updated || 'N/A',

  '🔄 WORKFLOWS ACTIVOS': '═══════════════════════════════',
  workflows: [
    'Enrichment Batch XX/10 (secuencial, 1 a la vez)',
    'Retry Failed Companies (cada 2h)',
    'Proxy Discover (cada 6h, SOCKS5)',
    'Proxy Validate (cada 30min)',
    'Logo Pipeline (cada 2h, 50/batch)'
  ],

  '📋 LAST 10': '═══════════════════════════════',
  recent: recent.map(r =>
    `${r.ruc} | ${(r.razon_social||'').substring(0,30)} | ${r.status} | ${r.fields||0} fields | ${r.tier} | ${r.error_type || 'ok'}`
  ),

  '🔄 RETRIES': '═══════════════════════════════',
  retry_summary: `${fixedByRetry} fixed | ${failedRetry} still failing | ${failed} pending retry`,

  '❌ FAILURES (top 20)': `${totalErrors} total`,
  failed_list: failures.map(f =>
    `${f.ruc} | ${(f.razon_social||'').substring(0,30)} | ${f.status} | [${f.error_type||'?'}] ${(f.error||'Unknown error').substring(0,50)}`
  )
}};
